from collections import defaultdict, deque

class Solution(object):
    def assignEdgeWeights(self, edges):
        MOD = 10**9 + 7
        n = len(edges) + 1  # number of nodes
        adj = defaultdict(list)
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        # BFS from node 1 to find max depth
        dist = [-1] * (n + 1)
        dist[1] = 0
        q = deque([1])
        while q:
            node = q.popleft()
            for nb in adj[node]:
                if dist[nb] == -1:
                    dist[nb] = dist[node] + 1
                    q.append(nb)

        max_depth = max(dist[1:])

        # Number of ways to choose odd number of 1s from max_depth edges = 2^(max_depth-1)
        if max_depth == 0:
            return 0
        return pow(2, max_depth - 1, MOD)
